    expect(content).to include('**bold**')
  end

  it 'code_block: Code block with language' do
    html = "<pre><code class=\"language-python\">print('hello')</code></pre>"
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content).to include('```python')
    expect(content).to include("print('hello')")
    expect(content).to include('```')
  end

  it 'heading_h1: H1 heading' do
    html = '<h1>Heading 1</h1>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).to eq('# Heading 1')
  end

  it 'heading_h2: H2 heading' do
    html = '<h2>Heading 2</h2>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).to eq('## Heading 2')
  end

  it 'heading_h3: H3 heading' do
    html = '<h3>Heading 3</h3>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).to eq('### Heading 3')
  end

  it 'heading_h4: H4 heading' do
    html = '<h4>Heading 4</h4>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).to eq('#### Heading 4')
  end

  it 'heading_h5: H5 heading' do
    html = '<h5>Heading 5</h5>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

    expect(content.strip).to eq('##### Heading 5')
  end

  it 'heading_h6: H6 heading' do
    html = '<h6>Heading 6</h6>'
    result = HtmlToMarkdown.convert(html)
    content = result[:content] || ''

